import clsx from 'clsx';

import {
  top as topStyle,
  magnifier,
  rotatedTopStyle,
} from './Magnifier.sty.js';
import { Magnifier } from './Magnifier.js';
import { useMagnifierPosition } from '../hooks/useMagnifierPosition.js';

export function TopMagnifier(
  props: Readonly<{
    label: string;
    mouseX: number;
    offset: number;
    color: string;
    chartBounds?: DOMRect;
    isRotated?: boolean;
  }>,
) {
  const { label, mouseX, color, chartBounds, isRotated } = props;

  const { magnifierPosition: left, magnifierRef } = useMagnifierPosition(
    mouseX,
    chartBounds?.left ?? 0,
    chartBounds?.right ?? 0,
    'horizontal',
    isRotated,
  );
  const top =
    (chartBounds?.top || 0) - (magnifierRef.current?.clientHeight || 0);

  return (
    <Magnifier
      aria-label="top axis magnifier"
      ref={magnifierRef}
      className={clsx(magnifier, isRotated ? rotatedTopStyle : topStyle)}
      style={{ top, left, backgroundColor: color }}
    >
      {label}
    </Magnifier>
  );
}
